import{_ as n,o as t,c as a,a0 as o}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Kho hàng","description":"","frontmatter":{"title":"Kho hàng"},"headers":[],"relativePath":"warehouse.md","filePath":"warehouse.md"}'),i={name:"warehouse.md"};function l(e,h,r,c,s,g){return t(),a("div",null,[...h[0]||(h[0]=[o(`<h1 id="kho-hang" tabindex="-1">Kho hàng <a class="header-anchor" href="#kho-hang" aria-label="Permalink to &quot;Kho hàng&quot;">​</a></h1><h2 id="gioi-thieu" tabindex="-1">Giới thiệu <a class="header-anchor" href="#gioi-thieu" aria-label="Permalink to &quot;Giới thiệu&quot;">​</a></h2><p>Kho hàng (Warehouse) là nơi lưu trữ hàng hóa, nguyên vật liệu và thành phẩm trong doanh nghiệp. ABNERP cho phép quản lý nhiều kho hàng với cấu trúc phân cấp linh hoạt, phù hợp với mọi mô hình kinh doanh từ kho trung tâm đến các điểm bán lẻ.</p><h2 id="cau-truc-kho-hang" tabindex="-1">Cấu trúc kho hàng <a class="header-anchor" href="#cau-truc-kho-hang" aria-label="Permalink to &quot;Cấu trúc kho hàng&quot;">​</a></h2><h3 id="kho-hang-phan-cap" tabindex="-1">Kho hàng phân cấp <a class="header-anchor" href="#kho-hang-phan-cap" aria-label="Permalink to &quot;Kho hàng phân cấp&quot;">​</a></h3><p>Kho hàng trong ABNERP có thể được tổ chức theo cấu trúc cây:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Công ty ABC</span></span>
<span class="line"><span>├── Kho Trung tâm</span></span>
<span class="line"><span>│   ├── Khu A — Hàng điện tử</span></span>
<span class="line"><span>│   ├── Khu B — Hàng thời trang</span></span>
<span class="line"><span>│   └── Khu C — Hàng tồn kho lâu</span></span>
<span class="line"><span>├── Kho Chi nhánh Hà Nội</span></span>
<span class="line"><span>├── Kho Chi nhánh Đà Nẵng</span></span>
<span class="line"><span>├── Kho Chi nhánh TP. HCM</span></span>
<span class="line"><span>└── Cửa hàng Bán lẻ</span></span>
<span class="line"><span>    ├── Cửa hàng Quận 1</span></span>
<span class="line"><span>    └── Cửa hàng Quận 7</span></span></code></pre></div><h3 id="cac-loai-kho" tabindex="-1">Các loại kho <a class="header-anchor" href="#cac-loai-kho" aria-label="Permalink to &quot;Các loại kho&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Loại kho</th><th>Mô tả</th><th>Ví dụ</th></tr></thead><tbody><tr><td>Kho chính</td><td>Kho trung tâm, dung lượng lớn</td><td>Kho tổng, Kho trung tâm</td></tr><tr><td>Kho trung chuyển</td><td>Hàng tạm thời, chờ chuyển tiếp</td><td>Kho cross-docking, bến cảng</td></tr><tr><td>Kho điểm bán</td><td>Hàng tại cửa hàng bán lẻ</td><td>Quầy thu ngân, kho cửa hàng</td></tr><tr><td>Kho sản xuất</td><td>Nguyên vật liệu/bán thành phẩm</td><td>Kho NVL, kho WIP</td></tr><tr><td>Kho hỏng/hủy</td><td>Hàng lỗi, hư hỏng chờ xử lý</td><td>Kho hàng lỗi, kho trả bảo hành</td></tr></tbody></table><h2 id="tao-va-quan-ly-kho-hang" tabindex="-1">Tạo và quản lý kho hàng <a class="header-anchor" href="#tao-va-quan-ly-kho-hang" aria-label="Permalink to &quot;Tạo và quản lý kho hàng&quot;">​</a></h2><h3 id="tao-kho-hang-moi" tabindex="-1">Tạo kho hàng mới <a class="header-anchor" href="#tao-kho-hang-moi" aria-label="Permalink to &quot;Tạo kho hàng mới&quot;">​</a></h3><ol><li>Truy cập: <strong>Kho &gt; Kho hàng &gt; Thêm mới</strong></li><li>Nhập thông tin: <ul><li><strong>Tên kho hàng</strong>: Tên hiển thị</li><li><strong>Kho cha</strong>: Chọn kho cấp trên (nếu có)</li><li><strong>Địa chỉ</strong>: Địa chỉ kho hàng</li><li><strong>Người phụ trách</strong>: Nhân viên quản lý kho</li><li><strong>Trạng thái</strong>: Đang hoạt động / Ngừng hoạt động</li></ul></li></ol><h3 id="chinh-sua-va-vo-hieu-hoa" tabindex="-1">Chỉnh sửa và vô hiệu hóa <a class="header-anchor" href="#chinh-sua-va-vo-hieu-hoa" aria-label="Permalink to &quot;Chỉnh sửa và vô hiệu hóa&quot;">​</a></h3><ul><li>Có thể chỉnh sửa thông tin kho hàng bất kỳ lúc nào</li><li>Kho hàng có tồn kho không thể xóa được — hãy vô hiệu hóa (Disable) thay thế</li><li>Khi vô hiệu hóa, kho sẽ không hiển thị trong danh sách chọn trên giao dịch mới</li></ul><h2 id="quan-ly-ton-kho-theo-kho" tabindex="-1">Quản lý tồn kho theo kho <a class="header-anchor" href="#quan-ly-ton-kho-theo-kho" aria-label="Permalink to &quot;Quản lý tồn kho theo kho&quot;">​</a></h2><h3 id="ton-kho-theo-tung-kho" tabindex="-1">Tồn kho theo từng kho <a class="header-anchor" href="#ton-kho-theo-tung-kho" aria-label="Permalink to &quot;Tồn kho theo từng kho&quot;">​</a></h3><p>ABNERP theo dõi tồn kho riêng biệt cho từng kho hàng. Cùng một mặt hàng có thể có số lượng và giá trị tồn khác nhau ở mỗi kho.</p><h3 id="chuyen-kho" tabindex="-1">Chuyển kho <a class="header-anchor" href="#chuyen-kho" aria-label="Permalink to &quot;Chuyển kho&quot;">​</a></h3><p>Khi cần điều chuyển hàng giữa các kho, sử dụng giao dịch <strong>Chuyển kho</strong> (Material Transfer):</p><ul><li>Chuyển từ kho A sang kho B</li><li>Hệ thống tự động ghi nhận giảm tồn kho nguồn và tăng tồn kho đích</li><li>Giá trị chuyển kho có thể tính theo giá bình quân hoặc giá nhập</li></ul><h3 id="bao-cao-ton-kho-theo-kho" tabindex="-1">Báo cáo tồn kho theo kho <a class="header-anchor" href="#bao-cao-ton-kho-theo-kho" aria-label="Permalink to &quot;Báo cáo tồn kho theo kho&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Báo cáo</th><th>Mô tả</th></tr></thead><tbody><tr><td>Số dư kho</td><td>Số lượng và giá trị tồn kho hiện tại</td></tr><tr><td>Nhập xuất tồn</td><td>Biến động tồn kho theo thời gian</td></tr><tr><td>Nhập xuất tồn theo kho</td><td>Biến động chi tiết của từng kho</td></tr><tr><td>Hàng tồn chậm luân chuyển</td><td>Hàng lưu kho lâu ngày</td></tr></tbody></table><h2 id="tich-hop" tabindex="-1">Tích hợp <a class="header-anchor" href="#tich-hop" aria-label="Permalink to &quot;Tích hợp&quot;">​</a></h2><p>Kho hàng được tích hợp chặt chẽ với các mô-đun khác:</p><ul><li><strong>Mua hàng</strong>: Chọn kho nhập trên chứng từ mua hàng</li><li><strong>Bán hàng</strong>: Chọn kho xuất trên đơn bán hàng, hóa đơn</li><li><strong>Sản xuất</strong>: Kho nguyên vật liệu và kho thành phẩm</li><li><strong>Bán lẻ (POS)</strong>: Kho của từng điểm bán</li></ul><h2 id="meo-quan-ly-kho-hieu-qua" tabindex="-1">Mẹo quản lý kho hiệu quả <a class="header-anchor" href="#meo-quan-ly-kho-hieu-qua" aria-label="Permalink to &quot;Mẹo quản lý kho hiệu quả&quot;">​</a></h2><ul><li>Sử dụng cấu trúc kho phân cấp để quản lý rõ ràng</li><li>Đặt tên kho theo quy tắc nhất quán</li><li>Kiểm kê định kỳ để đảm bảo khớp đúng giữa hệ thống và thực tế</li><li>Thiết lập tồn kho tối thiểu để nhận cảnh báo tái đặt hàng</li><li>Phân quyền người dùng chỉ truy cập được kho được phân công</li><li>Sử dụng báo cáo hàng tồn chậm luân chuyển để tối ưu vốn lưu động</li></ul>`,27)])])}const k=n(i,[["render",l]]);export{d as __pageData,k as default};
